import { NextRequest, NextResponse } from "next/server";

export const runtime = "nodejs"; // Important for Vercel

export async function POST(req: NextRequest) {
  try {
    const body = await req.json();
    const messages = body.messages || [];

    const apiKey = process.env.GEMINI_API_KEY;

    if (!apiKey) {
      return NextResponse.json(
        { error: "Missing GEMINI_API_KEY" },
        { status: 500 }
      );
    }

    // Convert OpenAI-style messages → Gemini format
    const geminiMessages = messages.map((m: any) => ({
      role: m.role === "assistant" ? "model" : "user",
      parts: [{ text: String(m.content) }]
    }));

    const response = await fetch(
      `https://generativelanguage.googleapis.com/v1/models/gemini-2.5-flash:generateContent?key=${apiKey}`,
      {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          contents: geminiMessages
        }),
      }
    );

    const data = await response.json();

    if (!response.ok) {
      console.error("Gemini API error:", data);
      return NextResponse.json(
        { error: "Gemini API error", details: data },
        { status: 500 }
      );
    }

    const rawText =
      data?.candidates?.[0]?.content?.parts
        ?.map((p: any) => p.text || "")
        .join(" ")
        .trim() || "";

    if (!rawText) {
      console.error("Gemini returned empty content:", data);
      return NextResponse.json(
        { error: "Empty response from Gemini", details: data },
        { status: 500 }
      );
    }
    // Extract Python code block for PlotVerter
    const codeMatch = rawText.match(/```(?:python)?\s*([\s\S]*?)```/i);
    const extractedCode = codeMatch ? codeMatch[1].trim() : rawText.trim();

    // Return BOTH formats:
    // - Guided Analysis uses choices[0].message.content
    // - PlotVerter uses output
    return NextResponse.json({
      output: extractedCode,
      choices: [
        {
          message: {
            role: "assistant",
            content: rawText
          }
        }
      ]
    });
  } catch (err) {
    console.error("Server error:", err);
    return NextResponse.json(
      { error: "Server error", details: String(err) },
      { status: 500 }
    );
  }
}
